  	RETURN 'ΣΥΝΤΑΞΗ ΓΗΡΑΤΟΣ';
  END IF;	
  	
end;

function CF_DISABLED_PERCENTAGEFormula return Char is
V_INCR_SEQ_NO_SR PEN_QT_PER_BE_CC_PER_ACCOUNT.DI_DEC_INCR_SEQ_NO%TYPE; V_DECISION_YEAR_SR PEN_QT_PER_BE_CC_PER_ACCOUNT.DI_DT_DECISION_YEAR%TYPE; V_DEC_UNIT_CODE_SR PEN_QT_PER_BE_CC_PER_ACCOUNT.DI_DT_DEC_UNIT_CODE%TYPE; V_DI_DT_DOCUMENT_TYPE_SR PEN_QT_PER_BE_CC_PER_ACCOUNT.DI_DT_DOCUMENT_TYPE_DEC_CODE%TYPE; V_VALUE1 PEN_DEC_FACT_TYPES_INSTANCE.VALUE%TYPE;
V_INCR_SEQ_NO_SR2 PEN_ACCOUNT.DI_DEC_INCR_SEQ_NO%TYPE; V_DECISION_YEAR_SR2 PEN_ACCOUNT.DI_DT_DECISION_YEAR%TYPE; V_DEC_UNIT_CODE_SR2 PEN_ACCOUNT.DI_DT_DEC_UNIT_CODE%TYPE; V_DI_DT_DOCUMENT_TYPE_SR2 PEN_ACCOUNT.DI_DT_DOCUMENT_TYPE_DEC_CODE%TYPE; V_ACCOUNT_NO_DEAD PEN_ACCOUNT.ACCOUNT_NO%TYPE;
CURSOR cur_ind_account IS SELECT A.ACCOUNT_NO FROM PEN_ACCOUNT A, PEN_ACCOUNT B, PEN_QC_PER_PRODINST C, PEN_PRODUCT_PER_INSTITUTIONS D WHERE A.INS_INSURED_ID = B.INS_INSURED_ID AND B.ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR AND A.TEMP_FLG = '0' AND A.USAGE_FLG = '1' AND NVL(A.CONVERTED_FLG,'0') != '1' AND A.QCPRODINS_QC_PER_PRODINST_CODE = C.QC_PER_PRODINST_CODE AND C.PRODUCT_PER_INSTITUTION_CODE = D.PRODUCT_PER_INSTITUTION_CODE AND D.PRODUCT_CODE IN ('00001', '00002') AND D.INSTITUTION_CODE = (SELECT H.INSTITUTION_CODE FROM PEN_ACCOUNT F, PEN_QC_PER_PRODINST G, PEN_PRODUCT_PER_INSTITUTIONS H WHERE F.QCPRODINS_QC_PER_PRODINST_CODE = G.QC_PER_PRODINST_CODE AND G.PRODUCT_PER_INSTITUTION_CODE = H.PRODUCT_PER_INSTITUTION_CODE AND F.ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR);
Cursor cur_get_keys IS SELECT A.DI_DEC_INCR_SEQ_NO, A.DI_DT_DECISION_YEAR, A.DI_DT_DEC_UNIT_CODE, A.DI_DT_DOCUMENT_TYPE_DEC_CODE
FROM PEN_QT_PER_BE_CC_PER_ACCOUNT A ,PEN_QUALIFYING_TERM_PER_BE_CC B ,PEN_QUALIFYING_TERM_PER_CC C ,PEN_BE_PER_CALCUL_CATEGORY D ,PEN_BE_PER_QUAL_CAT F ,PEN_BE_PER_PRODINST G ,PEN_BUSSINESS_EVENTS H WHERE A.acc_account_no = V_ACCOUNT_NO_DEAD --a palios toy pethamenou AND A.cc_per_be_type_per_decins_upd = '1' AND A.status = '1' AND H.state = '0' AND H.bussiness_event_group = '19' AND A.commit_date IS NOT NULL AND A.bcc_qual_term_per_be_cc_code = B.qual_term_per_be_cc_code AND B.qualif_term_per_cc_code = C.qualif_term_per_cc_code AND C.be_per_calcul_category_co = D.be_per_calcul_category_code AND D.be_per_qual_category_code = F.be_per_qual_category_code AND F.be_per_prodinst_code = G.be_per_prodinst_code AND G.buss_event_code = H.buss_event_code ORDER BY A.commit_date DESC, a.START_DATE DESC ;
CURSOR cur_get_keys2 IS SELECT A.DI_DEC_INCR_SEQ_NO, A.DI_DT_DECISION_YEAR, A.DI_DT_DEC_UNIT_CODE, A.DI_DT_DOCUMENT_TYPE_DEC_CODE FROM PEN_ACCOUNT A WHERE A.ACCOUNT_NO = V_ACCOUNT_NO_DEAD;
CURSOR cur_value1 IS SELECT value FROM pen_dec_fact_types_instance WHERE pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR = V_DI_DT_DOCUMENT_TYPE_SR AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = V_INCR_SEQ_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = V_DECISION_YEAR_SR AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = V_DEC_UNIT_CODE_SR AND pen_dec_fact_types_instance.dec_fact_type_code = '00200' and pen_dec_fact_types_instance.title_code ='00323';
CURSOR cur_value2 IS SELECT value FROM pen_dec_fact_types_instance WHERE pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR = V_DI_DT_DOCUMENT_TYPE_SR2 AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = V_INCR_SEQ_NO_SR2 AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = V_DECISION_YEAR_SR2 AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = V_DEC_UNIT_CODE_SR2 AND pen_dec_fact_types_instance.dec_fact_type_code = '00200' and pen_dec_fact_types_instance.title_code ='00035';
begin
OPEN cur_ind_account; FETCH cur_ind_account INTO V_ACCOUNT_NO_DEAD; CLOSE cur_ind_account;
OPEN cur_get_keys; FETCH cur_get_keys INTO V_INCR_SEQ_NO_SR , V_DECISION_YEAR_SR , V_DEC_UNIT_CODE_SR , V_DI_DT_DOCUMENT_TYPE_SR; CLOSE cur_get_keys;
IF V_INCR_SEQ_NO_SR IS NOT NULL THEN OPEN cur_value1; FETCH cur_value1 INTO V_VALUE1; CLOSE cur_value1; ELSE OPEN cur_get_keys2; FETCH cur_get_keys2 INTO V_INCR_SEQ_NO_SR2, V_DECISION_YEAR_SR2, V_DEC_UNIT_CODE_SR2, V_DI_DT_DOCUMENT_TYPE_SR2; CLOSE cur_get_keys2;
OPEN cur_value2; FETCH cur_value2 INTO V_VALUE1; CLOSE cur_value2;
END IF;
RETURN (100-TO_NUMBER(V_VALUE1) || '%'); end;

      function CF_267 return CHAR is
begin
    IF :P_FACTITIOUS_DATE >= '1/1/2003' THEN 
  	RETURN ('267Α');
  ELSE 
  	RETURN ('200στά');
  END IF;
end;

      function CF_10FORMULA0022 return Char is

--V_VALUE PEN_DEC_FACT_TYPES_INSTANCE.VALUE%TYPE;
V_REAL_ACCOUNT_NO PEN_ACCOUNT.ACCOUNT_NO%TYPE;
V_REDUCTION  NUMBER;
V_UNDER NUMBER;

CURSOR CUR_VALUE IS
SELECT NVL(FIND_DEAD_REAL_ACCOUNT(:P_ACC_ACCOUNT_NO_DIR),:P_ACC_ACCOUNT_NO_DIR)
FROM DUAL;

/*CURSOR CUR_VALUE is
SELECT value FROM pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code IN ('00070', '00071') AND 
pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DT_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND 
pen_dec_fact_types_instance.dec_fact_type_code = '00119';*/



begin
  
  OPEN  CUR_VALUE;
  FETCH CUR_VALUE
  INTO V_REAL_ACCOUNT_NO;
  CLOSE CUR_VALUE;

  PENBAT_IKA_CP_PROCEDURES.PENSION_REDUCTION(V_REAL_ACCOUNT_NO,0,1000,V_REDUCTION); 
   IF :P_FACTITIOUS_DATE >= '1/1/2003' THEN 
  	 V_UNDER:= 267;
  ELSE 
  	 V_UNDER:= 200;
  END IF;
  
  V_REDUCTION:= ROUND((V_UNDER/1000)*V_REDUCTION);
  
  RETURN V_REDUCTION;
  
end;

      function CF_10Formula return Char is

V_PRODUCT_CODE PEN_PRODUCTS.PRODUCT_CODE%TYPE;

Cursor cur_product_code IS
SELECT PEN_PRODUCTS.PRODUCT_CODE
FROM   PEN_BE_PER_PRODINST, 
	   PEN_PRODUCT_PER_INSTITUTIONS,
	   PEN_PRODUCTS
WHERE PEN_BE_PER_PRODINST.BE_PER_PRODINST_CODE=:P_BE_PER_PRODINST
AND PEN_BE_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE
AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE;

begin
 OPEN cur_product_code; 
 FETCH cur_product_code 
 INTO V_PRODUCT_CODE;
 CLOSE cur_product_code;

 RETURN V_PRODUCT_CODE;
 
end;

      function CF_AWARD_DESCRFORMULA return Char is

V_AWARD_FLAG PEN_DECISION_INSTANCE.AWARD_TYPE_FLAG%TYPE;
V_PROMPT     VARCHAR2(50);

Cursor cur_award_prompt Is
SELECT A.AWARD_TYPE_FLAG
FROM PEN_DECISION_INSTANCE A										 
WHERE A.DEC_INCR_SEQ_NO =:P_DECISION_NO
AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE_DIR
AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR_DIR
AND A.DT_DOCUMENT_TYPE_DEC_CODE='1';

begin
 
 OPEN cur_award_prompt;
   FETCH cur_award_prompt 
   INTO V_AWARD_FLAG;
 CLOSE cur_award_prompt;
 
 IF V_AWARD_FLAG ='0' THEN
 	  V_PROMPT:='απονομή';
 ELSE 	
 	  V_PROMPT:='τροποποίηση της απόφασης απονομής';
	END IF;
 
 RETURN V_PROMPT;
 
end;

      function CF_AWARD_FLGFormula return Char is

V_AWARD_FLAG PEN_DECISION_INSTANCE.AWARD_TYPE_FLAG%TYPE;

Cursor cur_award_prompt Is
SELECT A.AWARD_TYPE_FLAG
FROM PEN_DECISION_INSTANCE A										 
WHERE A.DT_DOCUMENT_TYPE_DEC_CODE='1'
AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE
AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR
AND A.DEC_INCR_SEQ_NO =:P_DECISION_NO;

begin
 
 OPEN cur_award_prompt;
   FETCH cur_award_prompt 
   INTO V_AWARD_FLAG;
 CLOSE cur_award_prompt;
 
 RETURN V_AWARD_FLAG;
 
end;

      function CF_00420Formula return Date is
v_calc_begin_date_varchar VARCHAR2(10);
V_DATE DATE;

	CURSOR Cur_is_new_assignee IS
	SELECT 1
	FROM PEN_DECISION_INSTANCE_DEATH A
	WHERE A.ACC_ACCOUNT_NO = :P_Acc_Account_No
	AND STATUS = '1'
	AND A.NEW_OLD_DEC IN ('NEW-INS','NEW');
	
  CURSOR Cur_death_start_date IS
	SELECT A.start_date
	FROM PEN_ACCOUNT A
	WHERE A.ACCOUNT_NO = :P_Acc_Account_No_Dir;	

	v_is_new_assignee_flg NUMBER:=0;

BEGIN

   OPEN Cur_is_new_assignee;
   FETCH Cur_is_new_assignee
   INTO v_is_new_assignee_flg;
   CLOSE Cur_is_new_assignee;

  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
			 0,0,'00001','00318','00420');
  	
  	IF v_is_new_assignee_flg = 1 THEN
					OPEN Cur_death_start_date;
				  FETCH Cur_death_start_date
				  INTO V_DATE;
				  CLOSE Cur_death_start_date;
		ELSE
			  V_DATE:= TO_DATE(v_calc_begin_date_varchar,'DD/MM/RRRR'); 
		END IF;
  
  
  
  IF v_calc_begin_date_varchar IS NOT NULL OR v_is_new_assignee_flg = 1  THEN 
    RETURN (V_DATE); 
  ELSE 
   RETURN '';
  END IF;
END;

      FUNCTION CF_PAYMENT_AMOUNTFormula RETURN NUMBER IS

v_calc_begin_date_varchar VARCHAR2(10);
v_calc_begin_date DATE;
V_AMOUNT NUMBER;

	CURSOR Cur_is_new_assignee IS
	SELECT 1
	FROM PEN_DECISION_INSTANCE_DEATH A
	WHERE A.ACC_ACCOUNT_NO = :P_Acc_Account_No
	AND STATUS = '1'
	AND A.NEW_OLD_DEC IN ('NEW-INS','NEW');
		
	CURSOR Cur_death_start_date IS
	SELECT A.start_date
	FROM PEN_ACCOUNT A
	WHERE A.ACCOUNT_NO = :P_Acc_Account_No_Dir;	

	v_is_new_assignee_flg NUMBER:=0;

BEGIN

   OPEN Cur_is_new_assignee;
   FETCH Cur_is_new_assignee
   INTO v_is_new_assignee_flg;
   CLOSE Cur_is_new_assignee;

	  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
					 0,0,'00001','00318','00420');

		IF v_calc_begin_date_varchar IS NOT NULL THEN
		   v_calc_begin_date := TO_DATE(v_calc_begin_date_varchar,'DD/MM/RRRR');
		END IF;

  	IF v_is_new_assignee_flg = 1 THEN
					OPEN Cur_death_start_date;
				  FETCH Cur_death_start_date
				  INTO v_calc_begin_date;
				  CLOSE Cur_death_start_date;
		END IF;

	V_AMOUNT := Penbat_Payments.Calc_Total_Scale_Raise_Back (NULL
																													 ,NULL
																													 ,v_calc_begin_date
																												 	 ,:P_ACC_START_DATE
																													 ,:P_PENSION_AMOUNT);
  
  RETURN (ROUND(V_AMOUNT,2)+:P_PENSION_AMOUNT); 
  
  
END;

      function CF_PROTOCOL_CASEFormula return Char is
V_STRING VARCHAR2(300);
V_PROTOCOL_NO     PEN_DECISION_INSTANCE.CONVERT_PROTOCOL_NO%TYPE;
V_PROTOCOL_DATE   PEN_DECISION_INSTANCE.CONVERT_PROTOCOL_DATE%TYPE;

-- CHRYS 9/11/2020
CURSOR CUR_PRODUCT IS
SELECT C.PRODUCT_CODE
FROM   PEN_ACCOUNT A,PEN_QC_PER_PRODINST B, PEN_PRODUCT_PER_INSTITUTIONS C
WHERE  A.ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
AND    A.QCPRODINS_QC_PER_PRODINST_CODE = B.QC_PER_PRODINST_CODE
AND    B.PRODUCT_PER_INSTITUTION_CODE = C.PRODUCT_PER_INSTITUTION_CODE;

V_PRODUCT_CODE  PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE%TYPE;
V_TEXT VARCHAR2(200);
-- END CHRYS 9/11/2020

--SPAP 12/2020 EMAIL BY 02/12/2020 PSYCHOGIOS
CURSOR C_PROTOCOL IS
SELECT A.PROTOCOL_NO||'-'||TO_CHAR(B.APPL_DATE,'DD/MM/RRRR')
FROM PEN_DECISION_INSTANCE A,
	   PEN_APPLICATION_INSTANCES B 										 
WHERE A.DEC_INCR_SEQ_NO                = :P_DECISION_NO
  AND A.DT_DEC_UNIT_CODE               = :P_DT_DEC_UNIT_CODE  
	AND A.DT_DECISION_YEAR               = :P_DT_DECISION_YEAR  
	AND A.DT_DOCUMENT_TYPE_DEC_CODE      = '1' 
	AND A.PAI_PDTA_APPLICATION_UNIT_CODE = B.PDTA_APPLICATION_UNIT_CODE
  AND A.PAI_PDTA_APPLICATION_YEAR      = B.PDTA_APPLICATION_YEAR
  AND A.PAI_APPLICATION_INCR_SEQ_NO    = B.APPLICATION_INCR_SEQ_NO;

V_PROT VARCHAR2(100);
--SPAP

begin                 
-- CHRYS 9/11/2020
	OPEN 	CUR_PRODUCT;
	FETCH	CUR_PRODUCT
	INTO	V_PRODUCT_CODE;
	CLOSE	CUR_PRODUCT;
	
	IF V_PRODUCT_CODE = '00003' THEN
		V_TEXT := 'απονομή λόγω θανάτου';
	ELSIF V_PRODUCT_CODE IN ( '00003', '00004' ) THEN
		V_TEXT := 'μεταβίβαση λόγω θανάτου';
	END IF;
-- END CHRYS 9/11/2020

  OPEN C_PROTOCOL;
  FETCH C_PROTOCOL INTO V_PROT;
  CLOSE C_PROTOCOL;

	IF :CF_AWARD_FLG!='0' THEN 
	  SELECT A.CONVERT_PROTOCOL_NO ,
		       A.CONVERT_PROTOCOL_DATE
	  INTO V_PROTOCOL_NO,
	       V_PROTOCOL_DATE
		FROM PEN_DECISION_INSTANCE A										 
		WHERE A.DEC_INCR_SEQ_NO =:P_DECISION_NO
		AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE   --_DIR
		AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR  --_DIR
		AND A.DT_DOCUMENT_TYPE_DEC_CODE='1';
 END IF;
	
	if :P_POLLAPLI_THANATOU = 1 then
			
	  V_STRING := V_PROT;
	  
	else 	
		
		IF :CF_AWARD_FLG='0' THEN 
			IF :PROTOCOL_NO IS NOT NULL THEN 
		     --V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| :PEN_APPLICATION_INSTANCES_PROT || ' αίτηση για '||v_text||',';-- chrys 9/11/2020 μεταβίβαση λόγω θανάτου,' ;  ---SPAP 12/2020 
		     V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| V_PROT || ' αίτηση για '||v_text||',';-- chrys 9/11/2020 μεταβίβαση λόγω θανάτου,' ;
		 ELSE 
		     V_STRING := 'οίκοθεν την περίπτωση για '||v_text||',';-- chrys 9/11/2020 μεταβίβαση λόγω θανάτου,';
		  END IF;    
		ELSE
		 	IF V_PROTOCOL_NO IS NOT NULL THEN 
		     V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| V_PROTOCOL_NO ||'-'||V_PROTOCOL_DATE ||  ' αίτηση για '||v_text||',';-- chrys 9/11/2020 μεταβίβαση λόγω θανάτου,' ;
		 ELSE 
		     V_STRING := 'οίκοθεν την περίπτωση για '||v_text||',';-- chrys 9/11/2020 μεταβίβαση λόγω θανάτου,';
		  END IF;    
		END IF;
	
	end if;
  return (V_STRING);
end;

      function CF_REASONFormula return Char is

v_DESCR  VARCHAR2(100);
v_calc_begin_date_varchar   VARCHAR2(10);

	     
	     

begin

v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
             0,0,'00001','01180','01011');


 --COMBAT_DEBUGING('v_calc_begin_date_varchar = '||v_calc_begin_date_varchar, 'CHRYS_REPORTS');
 
 IF v_calc_begin_date_varchar IS NOT NULL THEN
	 SELECT PROCUCT_DESCRIPTION
	 INTO   v_DESCR
	 FROM   PEN_PRODUCTS
	 WHERE   PEN_PRODUCTS.product_code = v_calc_begin_date_varchar
	 ORDER BY   PEN_PRODUCTS.product_code;
END IF;

  RETURN v_DESCR;
end;

      function CF_INSURANCE_DAYSFormula return Number is

 V_RESULT NUMBER;
 V_YEAR   NUMBER;

CURSOR cur_INS_DAYS IS 
 SELECT A.VALUE
 FROM
       PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '00367' AND
	     A.Dec_Fact_Type_Code = '00500';

CURSOR cur_YEAR IS
SELECT INSURANCE_YEARS
FROM  PEN_CALC_NATIONAL_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;


begin

  OPEN cur_INS_DAYS;
  FETCH cur_INS_DAYS
  INTO V_RESULT;
  CLOSE cur_INS_DAYS;
  
  OPEN cur_YEAR;
  FETCH cur_YEAR
  INTO V_YEAR;
  CLOSE cur_YEAR;
  
  
   IF :P_Acc_Account_No_DIR IS NOT NULL THEN 
        RETURN (V_YEAR*300);
   ELSE
   	 RETURN V_RESULT;
   END IF; 
  
end;

