      function CF_10FORMULA0009 return VARCHAR2 is
 V_RESULT NUMBER;
 V_PROMPT VARCHAR2(50);

CURSOR cur_INS_CLASS IS 
SELECT A.VALUE
FROM
    PEN_DEC_FACT_TYPES_INSTANCE A,
    PEN_ACCOUNT B
WHERE
    A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
    A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
    A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
    A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
    B.Account_No = :P_Acc_Account_No_DIR AND
    A.Title_Code         = '00367' AND
    A.Dec_Fact_Type_Code = '00525';

begin

  OPEN cur_INS_CLASS;
  FETCH cur_INS_CLASS
  INTO V_RESULT;
  CLOSE cur_INS_CLASS;
  
 IF nvl(V_RESULT,0) != 1  THEN
 	  V_PROMPT:= 'OXI';
 ELSIF 	V_RESULT = 1 THEN
 	  V_PROMPT :='NAI';
 END IF;
 
 RETURN V_PROMPT;
 
 
end;

