	    V_DISPLAY:='ΣΥΝΤΑΞΗΣ ΛΟΓΩ ΘΑΝΑΤΟΥ';
	  ELSIF V_DATE IS NOT NULL THEN 
	  	V_DISPLAY:='ΣΥΝΤΑΞΗΣ ΛΟΓΩ ΦΥΛΑΚΙΣΗΣ';
    END IF;
  END IF;
END IF;


return v_display;
end;

