      function CF_COMPLETE_55Formula return Date is

CURSOR CUR_COMPLETE_55 IS
SELECT ADD_MONTHS(DATE_OF_BIRTH, 55*12)
FROM REG_INSURED
WHERE INSURED_ID = :P_INSURED_ID_IND;

V_DATE	DATE;
begin
  OPEN CUR_COMPLETE_55;
  FETCH CUR_COMPLETE_55
  INTO V_DATE;
  CLOSE CUR_COMPLETE_55;
  
  RETURN V_DATE;
end;

