      function CF_14Formula return Number is

 v_NUM NUMBER;
    
CURSOR 	Cur_NUM IS
SELECT 	NVL(OLD_AMOUNT,0) 
			- NVL(SPECIAL_CONTRIBUTION,0) 
			- NVL(SPECIAL_CONTR_BEF_60,0) 
			- NVL(SPECIAL_CONTR_112011,0) 
			- NVL(AMNT_4051,0)
			- NVL(AMNT_4093,0) 
			- NVL(SICKNESS_DEDUCTION,0)
			- NVL(AMNT_NAT,0)
FROM PEN_EFKA_PERSONAL_DIFFERENCE
WHERE ACCOUNT_NO =:P_Acc_Account_No_Dir;   

begin
  
  
                 OPEN Cur_NUM;
                  FETCH Cur_NUM
                  INTO v_NUM;
                  CLOSE Cur_NUM;
                  
             RETURN ROUND(v_NUM,2);
            
	     
end;

