  	srw.message(100, ':CF_PLAFON_AMT : '||:CF_PLAFON_AMT);
		srw.message(100, ':CF_20 : '||:CF_20);
		srw.message(100, ':CF_21 : '||:CF_21);		
		srw.message(100, ':CF_19 : '||:CF_19);
