		srw.message(100, ':CF_OLD_KATAV_DIKAIOD : '||:CF_OLD_KATAV_DIKAIOD);*/
	
  	IF NVL(:CF_32,0) > 0 THEN 
	    -- CHRYS 25/11/2024 RETURN :CF_32;
	    RETURN nvl(:CF_32,0) - nvl(:CF_PLAFON_AMT,0); -- CHRYS 25/11/2024
	  ELSE
	  	-- CHRYS 25/4/2024 RETURN (NVL(:CF_20,0) + NVL(:CF_21,0) + NVL(:CF_19,0)) /* CHRYS 5/7/2021 */ + NVL(:CF_56,0);
	  	 -- CHRYS 25/11/2024 RETURN GREATEST( (NVL(:CF_20,0) + NVL(:CF_21,0) + NVL(:CF_19,0)) /* CHRYS 5/7/2021 */ + NVL(:CF_56,0), :CF_OLD_KATAV_DIKAIOD    ); -- CHRYS 25/4/2024
	  	 RETURN ( GREATEST( (NVL(:CF_20,0) + NVL(:CF_21,0) + NVL(:CF_19,0)) /* CHRYS 5/7/2021 */ + NVL(:CF_56,0), nvl(:CF_OLD_KATAV_DIKAIOD,0)    ) - NVL(:CF_PLAFON_AMT,0)); -- CHRYS 25/4/2024
	  END IF;			
    EXCEPTION WHEN OTHERS THEN RETURN NULL;
end;

