SELECT DISTINCT OLD_AMT_PRO_FOROU_THAN
FROM  PEN_CALC_NAT_LOWEST_DIKAIOD
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
AND ACCOUNT_NO_DIKAIOD = :P_ACC_ACCOUNT_NO;

CURSOR 	CUR_EXISTS_ODL_KATAV IS
SELECT 	NVL(AMOUNT,0)
FROM 		PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE		ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND		  STATUS = '1'
AND		  CC_PER_BE_TYPE_PER_DECINS_UPD = '1'
AND			CP_CALCULATION_PARAMETER_CODE = 'EMKBF';


begin
	/* CHRYS 13/11/2024 
  OPEN cur_OLD_KATAV;
  FETCH cur_OLD_KATAV
  INTO V_AMOUNT;
  CLOSE cur_OLD_KATAV;
  RETURN :P_PERCENTAGE*V_AMOUNT/100;
 
END CHRYS 13/11/2024 */
  
-- CHRYS 13/11/2024
  OPEN CUR_EXISTS_ODL_KATAV;
  FETCH CUR_EXISTS_ODL_KATAV
  INTO V_AMOUNT;
  CLOSE CUR_EXISTS_ODL_KATAV;
  RETURN NVL(V_AMOUNT,0);

-- END CHRYS 13/11/2024

  
end;

