      function CF_28Formula return Number is

V_NUM	  NUMBER;
V_NUM_0	  NUMBER;
V_NUM_1	NUMBER;
V_NUM_2	NUMBER;

CURSOR CUR IS
SELECT  (sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25),sum(NVL(MONTH_DAYS,0))
FROM PEN_CALC_ADAPOD_RES_EE
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
AND   AYTOT_TMHM_FLG  = '1';

CURSOR CUR_1 IS
SELECT   NVL(POSOSTO_ANAPL,0)+ NVL(ADAPOD_PERCENT_KSB,0)
FROM  PEN_CALC_ADAPOD_RES_EE
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
AND   AYTOT_TMHM_FLG  = '1';

CURSOR CUR_2 IS
SELECT ADAPODOTIKH_AMT
FROM   PEN_CALC_ADAPOD_RES_EE
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
AND   AYTOT_TMHM_FLG  = '1';


begin
  COMBAT_dEBUGING('IN CF_28', 'CHRYS_1402');
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM, V_NUM_0;
  CLOSE CUR;
  
  IF V_NUM_0 != 0 THEN
  	V_NUM := V_NUM/V_NUM_0;
  END IF;
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  OPEN CUR_2;
  FETCH CUR_2 
  INTO V_NUM_2;
  CLOSE CUR_2;
  
  COMBAT_dEBUGING('V_NUM_2 = '||V_NUM_2, 'CHRYS_1402');
  IF V_NUM_2 IS NOT NULL AND V_NUM_2 != 0 THEN
  	RETURN V_NUM_2;
  ELSE
	  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  END IF;
  

END;

