V_SYMFEROTERO      VARCHAR2(100);

begin
  OPEN CUR_BEST;
  FETCH CUR_BEST
  INTO V_BEST;
  CLOSE CUR_BEST;
  
  IF V_BEST = '1' THEN 
  	V_SYMFEROTERO := 'ΑΥΤΟΤΕΛΕΣ ΠΟΣΟ ΣΥΝΤΑΞΗΣ';
  ELSIF V_BEST = '2' THEN 
  	V_SYMFEROTERO := 'ΑΝΑΛΟΓΙΚΟ ΠΟΣΟ ΣΥΝΤΑΞΗΣ';
  END IF;	
  
  RETURN V_SYMFEROTERO;
end;

