      function CF_PLAFON_AMTFormula return Number is
v_NUM NUMBER;
-- CHRYS 5/7/2021    
CURSOR 	CUR_AMOUNT_PLAFON IS
SELECT 	AMOUNT
FROM 		PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE	 	ACC_ACCOUNT_NO =:P_ACC_ACCOUNT_NO
AND			CP_CALCULATION_PARAMETER_CODE = 'EMPLF'
AND     CC_PER_BE_TYPE_PER_DECINS_UPD = '1';   

begin
	OPEN 	CUR_AMOUNT_PLAFON;
	FETCH CUR_AMOUNT_PLAFON
  INTO 	v_NUM;
  CLOSE CUR_AMOUNT_PLAFON;
                  
  RETURN v_NUM;
END ;

      function CF_56Formula return Number is

v_NUM NUMBER;

CURSOR  CUR_AMOUNT_DIAFR IS
SELECT  AMOUNT
FROM    PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE   ACC_ACCOUNT_NO =:P_ACC_ACCOUNT_NO_DIR
AND     CP_CALCULATION_PARAMETER_CODE = 'DDIAF'
AND     CC_PER_BE_TYPE_PER_DECINS_UPD = '1';   

begin
  OPEN  CUR_AMOUNT_DIAFR;
  FETCH CUR_AMOUNT_DIAFR
  INTO  v_NUM;
  CLOSE CUR_AMOUNT_DIAFR;

   RETURN (NVL(v_NUM,0) * NVL(:P_PERCENTAGE/100,0));
end;

      function M_146FormatTrigger return boolean is
begin
  IF :P_BRANCH_CODE != '09930' THEN
  	return (false);
  ELSE
  	return (true);
  END IF;
end;

      function M_147FormatTrigger return boolean is
